import React, { useState } from "react";

const ProductReviews = ({ reviews, onSubmitReview }) => {
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");

  const handleSubmit = () => {
    onSubmitReview({ rating, comment });
    setComment("");
  };

  return (
    <div>
      {reviews.length === 0 && (
        <p className="text-gray-500 mb-4">Chưa có đánh giá nào.</p>
      )}

      {/* FORM ĐÁNH GIÁ */}
      <div className="p-4 bg-pink-50 rounded-xl mb-6">
        <p className="font-semibold mb-2">Viết đánh giá của bạn</p>

        <select
          className="border p-2 rounded mb-2"
          value={rating}
          onChange={(e) => setRating(e.target.value)}
        >
          {[5,4,3,2,1].map(r => (
            <option key={r} value={r}>{r} sao</option>
          ))}
        </select>

        <textarea
          value={comment}
          onChange={(e) => setComment(e.target.value)}
          className="border p-2 w-full rounded"
          placeholder="Nội dung đánh giá..."
        />

        <button
          onClick={handleSubmit}
          className="mt-2 bg-pink-600 text-white px-4 py-2 rounded"
        >
          Gửi đánh giá
        </button>
      </div>

      {/* LIST REVIEW */}
      <div className="space-y-4">
        {reviews.map((r, i) => (
          <div key={i} className="p-4 border rounded-lg bg-white">
            <p className="font-bold">⭐ {r.rating}</p>
            <p>{r.comment}</p>

            {r.adminReply && (
              <p className="mt-2 text-sm text-blue-600">
                💬 Admin: {r.adminReply}
              </p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductReviews;
